const webhookData = $('Webhook Trigger').first().json.body;
const theme = webhookData.theme;
const project_id = webhookData.project_id;

if (!project_id || !theme) {
  throw new Error('Missing project_id or theme in webhook body: ' + JSON.stringify(webhookData));
}

const groqBody = {
  model: 'llama-3.3-70b-versatile',
  max_tokens: 4096,
  temperature: 0.7,
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content: 'Tu es un auteur de livres pour enfants de 8 ans. Tu reponds UNIQUEMENT en JSON valide. Pas de texte avant ou apres le JSON. Pas de markdown.'
    },
    {
      role: 'user',
      content: 'Genere une courte histoire pour enfants sur le theme : "' + theme + '".

Decoupe-la en exactement 3 scenes.

Reponds avec ce JSON exact :
{
  "story": "texte complet de histoire",
  "moral": "la morale",
  "scenes": [
    {
      "scene_number": 1,
      "visual_description": "A colorful cartoon scene showing...",
      "narration": "texte de narration en francais",
      "duration_seconds": 10
    },
    {
      "scene_number": 2,
      "visual_description": "A bright animated scene where...",
      "narration": "texte de narration en francais",
      "duration_seconds": 10
    },
    {
      "scene_number": 3,
      "visual_description": "A cheerful cartoon finale with...",
      "narration": "texte de narration en francais",
      "duration_seconds": 10
    }
  ]
}'
    }
  ]
};

return [{ json: { project_id, theme, groqBody } }];

const project_id = $('Build Groq Request').first().json.project_id;
const theme = $('Build Groq Request').first().json.theme;

// With responseFormat 'json', N8N auto-parses the HTTP response body
const groqResponse = $input.first().json;

// The Groq API response structure: { choices: [{ message: { content: '...' } }] }
let rawContent = '';
try {
  rawContent = groqResponse.choices[0].message.content;
} catch (e) {
  throw new Error('Cannot read Groq response structure. Keys: ' + Object.keys(groqResponse || {}).join(', ') + ' | Full: ' + JSON.stringify(groqResponse).slice(0, 500));
}

if (!rawContent || rawContent.trim().length === 0) {
  throw new Error('Groq returned empty content');
}

// Clean: remove any markdown code fences just in case
let cleaned = rawContent.trim();
cleaned = cleaned.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse story JSON: ' + e.message + ' | Content: ' + cleaned.slice(0, 300));
}

if (!parsed.scenes || !Array.isArray(parsed.scenes) || parsed.scenes.length === 0) {
  throw new Error('No scenes array in parsed response. Keys: ' + Object.keys(parsed).join(', '));
}

// Normalize scenes
const scenes = parsed.scenes.map((s, i) => ({
  scene_number: s.scene_number || (i + 1),
  visual_description: s.visual_description || 'A colorful cartoon scene for children',
  narration: s.narration || '',
  duration_seconds: s.duration_seconds || 10
}));

return [{
  json: {
    project_id,
    theme,
    story: parsed.story || '',
    moral: parsed.moral || '',
    scenes
  }
}];

// Generate ElevenLabs TTS for each scene sequentially
const data = $('Parse Groq Response').first().json;
const project_id = data.project_id;
const scenes = data.scenes;
const ELEVENLABS_KEY = $vars.ELEVENLABS_API_KEY;
const ELEVENLABS_VOICE = $vars.ELEVENLABS_VOICE_ID;
const LARAVEL_URL = $vars.LARAVEL_URL;
const SECRET = $vars.N8N_WEBHOOK_SECRET;

// Notify step 3
try {
  await fetch(LARAVEL_URL + '/api/n8n/step', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'X-N8N-Secret': SECRET },
    body: JSON.stringify({ project_id, step: 3 })
  });
} catch(e) { /* ignore notification errors */ }

const results = [];

for (const scene of scenes) {
  let audioOk = false;
  try {
    const ttsRes = await fetch('https://api.elevenlabs.io/v1/text-to-speech/' + ELEVENLABS_VOICE, {
      method: 'POST',
      headers: {
        'xi-api-key': ELEVENLABS_KEY,
        'Content-Type': 'application/json',
        'Accept': 'audio/mpeg'
      },
      body: JSON.stringify({
        text: scene.narration,
        model_id: 'eleven_multilingual_v2',
        voice_settings: { stability: 0.7, similarity_boost: 0.8 }
      })
    });
    audioOk = ttsRes.ok;
  } catch(e) {
    audioOk = false;
  }

  results.push({
    scene_number: scene.scene_number,
    visual_description: scene.visual_description,
    narration: scene.narration,
    duration_seconds: scene.duration_seconds,
    audio_generated: audioOk
  });
}

return [{
  json: {
    project_id,
    theme: data.theme,
    story: data.story,
    moral: data.moral,
    scenes: results
  }
}];

// Create Replicate predictions for each scene, then poll until done
const data = $input.first().json;
const project_id = data.project_id;
const scenes = data.scenes;
const REPLICATE_TOKEN = $vars.REPLICATE_API_TOKEN;
const LARAVEL_URL = $vars.LARAVEL_URL;
const SECRET = $vars.N8N_WEBHOOK_SECRET;

// Notify step 4
try {
  await fetch(LARAVEL_URL + '/api/n8n/step', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'X-N8N-Secret': SECRET },
    body: JSON.stringify({ project_id, step: 4 })
  });
} catch(e) { /* ignore */ }

const sceneResults = [];

for (const scene of scenes) {
  let videoUrl = '';
  try {
    // Create prediction
    const createRes = await fetch('https://api.replicate.com/v1/models/minimax/video-01/predictions', {
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + REPLICATE_TOKEN,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        input: {
          prompt: scene.visual_description
        }
      })
    });

    const createData = await createRes.json();
    const predictionId = createData.id;

    if (!predictionId) {
      throw new Error('No prediction ID returned: ' + JSON.stringify(createData).slice(0, 200));
    }

    // Poll for completion (max 20 attempts = ~5 minutes)
    let status = 'starting';
    let output = null;
    for (let attempt = 0; attempt < 20; attempt++) {
      // Wait 15 seconds between polls
      await new Promise(resolve => setTimeout(resolve, 15000));

      const pollRes = await fetch('https://api.replicate.com/v1/predictions/' + predictionId, {
        headers: { 'Authorization': 'Bearer ' + REPLICATE_TOKEN }
      });
      const pollData = await pollRes.json();
      status = pollData.status;

      if (status === 'succeeded') {
        output = pollData.output;
        break;
      } else if (status === 'failed' || status === 'canceled') {
        throw new Error('Replicate prediction ' + status + ': ' + (pollData.error || 'unknown'));
      }
      // else starting/processing -> continue polling
    }

    if (status === 'succeeded' && output) {
      // output can be a string URL or an array
      videoUrl = Array.isArray(output) ? output[0] : String(output);
    } else if (status !== 'succeeded') {
      throw new Error('Replicate timed out after 20 polls, status: ' + status);
    }
  } catch(e) {
    videoUrl = 'error: ' + e.message;
  }

  sceneResults.push({
    scene_number: scene.scene_number,
    visual_description: scene.visual_description,
    narration: scene.narration,
    duration_seconds: scene.duration_seconds,
    video_url: videoUrl
  });
}

return [{
  json: {
    project_id,
    theme: data.theme,
    story: data.story,
    moral: data.moral,
    scenes: sceneResults
  }
}];

// Build the final callback payload and send to Laravel
const data = $input.first().json;
const project_id = data.project_id;
const story = data.story || '';
const scenes = data.scenes || [];

// Find the first valid video URL
let videoUrl = '';
for (const s of scenes) {
  if (s.video_url && !s.video_url.startsWith('error:')) {
    videoUrl = s.video_url;
    break;
  }
}

// Build scenes_json matching Laravel validation
const scenesJson = scenes.map(s => ({
  scene_number: s.scene_number,
  narration: s.narration || '',
  visual_description: s.visual_description || '',
  duration_seconds: s.duration_seconds || 10,
  video_url: s.video_url || ''
}));

const LARAVEL_URL = $vars.LARAVEL_URL;
const SECRET = $vars.N8N_WEBHOOK_SECRET;

// Send final callback
const callbackRes = await fetch(LARAVEL_URL + '/api/n8n/callback', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
    'X-N8N-Secret': SECRET
  },
  body: JSON.stringify({
    project_id: project_id,
    video_url: videoUrl || 'https://no-video-generated.example.com/placeholder',
    story_text: story,
    scenes_json: scenesJson
  })
});

const callbackBody = await callbackRes.text();

return [{
  json: {
    project_id,
    callback_status: callbackRes.status,
    callback_response: callbackBody,
    video_url: videoUrl,
    total_scenes: scenes.length
  }
}];

// Error handler: notify Laravel that the pipeline failed
const LARAVEL_URL = $vars.LARAVEL_URL;
const SECRET = $vars.N8N_WEBHOOK_SECRET;

// Try to extract project_id from various possible sources
let project_id = null;
try { project_id = $('Webhook Trigger').first().json.body.project_id; } catch(e) {}
if (!project_id) {
  try { project_id = $('Build Groq Request').first().json.project_id; } catch(e) {}
}

const errorMessage = $input.first().json?.error?.message || $input.first().json?.message || 'Unknown pipeline error';

if (project_id) {
  try {
    await fetch(LARAVEL_URL + '/api/n8n/error', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
        'X-N8N-Secret': SECRET
      },
      body: JSON.stringify({
        project_id: project_id,
        error_message: String(errorMessage).slice(0, 2000)
      })
    });
  } catch(e) {
    // Cannot notify Laravel, nothing we can do
  }
}

return [{ json: { project_id, error: errorMessage, notified: !!project_id } }];
